/* ═══ PRIMITIVES ═══ */
function Spark({data,color,w=100,h=28}:{data:number[];color:string;w?:number;h?:number}){const mx=Math.max(...data),mn=Math.min(...data),r=mx-mn||1;const pts=data.map((v,i)=>`${(i/(data.length-1))*w},${h-((v-mn)/r)*h}`).join(" ");return<svg width={w} height={h} className="overflow-visible"><polyline points={pts} fill="none" stroke={color} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/><circle cx={w} cy={h-((data[data.length-1]-mn)/r)*h} r="2.5" fill={color}/></svg>;}
function Dot({s}:{s:"on"|"warn"|"crit"|"off"}){const c={on:"bg-emerald-400",warn:"bg-amber-400",crit:"bg-red-400",off:"bg-slate-500"};return<span className="relative flex h-2 w-2">{s==="on"&&<span className={`animate-ping absolute inline-flex h-full w-full rounded-full ${c[s]} opacity-75`}/>}<span className={`relative inline-flex rounded-full h-2 w-2 ${c[s]}`}/></span>;}

function DrillCard({title,value,unit,change,spark,color,icon,children}:{title:string;value:string;unit?:string;change:number;spark:number[];color:string;icon:ReactNode;children:ReactNode}){
  const[open,setOpen]=useState(false);
  return(<Dialog open={open} onOpenChange={setOpen}><DialogTrigger asChild>
    <div className="group relative bg-[#0f1923] border border-[#1e2d3d] rounded-lg p-4 hover:border-[#2a4a6b] transition-all cursor-pointer overflow-hidden">
      <div className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity" style={{background:`radial-gradient(ellipse at 50% 0%,${color}08 0%,transparent 70%)`}}/>
      <div className="relative z-10">
        <div className="flex items-start justify-between mb-2"><div className="flex items-center gap-2"><span className="opacity-60">{icon}</span><span className="text-[10px] uppercase tracking-[0.1em] text-[#6b8aad] font-medium">{title}</span></div><div className={`flex items-center gap-1 text-[10px] font-medium ${change>=0?"text-emerald-400":"text-red-400"}`}><span>{change>=0?"\u2191":"\u2193"}</span>{Math.abs(change)}%</div></div>
        <div className="flex items-end justify-between"><div><div className="text-xl font-semibold text-[#e8f0f8]">{value}<span className="text-xs text-[#6b8aad] ml-1">{unit}</span></div></div><Spark data={spark} color={color}/></div>
        <div className="text-[10px] text-[#3a5a7a] mt-1 flex items-center gap-1">Click to drill down <I.ChevR/></div>
      </div>
    </div>
  </DialogTrigger><DialogContent className="bg-[#0a1218] border-[#1e2d3d] text-[#c8dff0] max-w-3xl max-h-[80vh] overflow-y-auto"><DialogHeader><DialogTitle className="text-[#e8f0f8] flex items-center gap-2">{icon} {title}</DialogTitle></DialogHeader>{children}</DialogContent></Dialog>);
}

function DrillRow({label,children}:{label:string;children:ReactNode}){const[open,setOpen]=useState(false);return(<div className="border-b border-[#162535] last:border-0"><button onClick={()=>setOpen(!open)} className="w-full flex items-center gap-3 py-2.5 text-xs text-[#a8c8e0] hover:text-[#e8f0f8] transition-colors"><I.ChevR className={`transition-transform shrink-0 ${open?"rotate-90":""}`}/><span className="flex-1 text-left">{label}</span></button>{open&&<div className="pl-7 pb-3 text-[11px] text-[#6b8aad] space-y-2 animate-in fade-in slide-in-from-top-1 duration-200">{children}</div>}</div>);}

