/* ═══ AGENT ═══ */
type Msg={role:"user"|"agent"|"sys";content:string;ts:string;actions?:string[]};
function AgentPanel(){
  const[msgs,setMsgs]=useState<Msg[]>([{role:"sys",content:"Language Services Agent online.\nConnected: Epic, Interpreter CMS, Census/USCIS, Vendor APIs, Patient Satisfaction, Financial.\n6 data sources. Modality routing, demand forecasting, and vendor intelligence active.",ts:"09:00"}]);
  const[inp,setInp]=useState("");const[thinking,setThinking]=useState(false);const ref=useRef<HTMLDivElement>(null);
  const respond=(q:string)=>{setThinking(true);const ql=q.toLowerCase();let r={content:"Searching 6 connected systems...\n\nAsk about demand forecasts, vendor SLAs, modality routing, census trends, cost optimization, or regulatory updates.",actions:["Full domain scan","Executive brief"]};
    if(ql.includes("demand")||ql.includes("forecast")||ql.includes("predict"))r={content:"\u{1F4CA} Demand Forecast\n\nMandarin: +40% at Carolinas MC (Mar 17-28)\nDari/Pashto: will exceed IL capacity by Q3\nASL rural WI: plateauing, shift to in-person recommended\n\nTotal LEP growth: 1.82M \u2192 2.34M by 2030\nFastest: Arabic (+34.2%), Dari (+28.7%)\n\n\u26A0\uFE0F 4 Dari/Pashto FTEs needed by Q3.",actions:["View full forecast","Activate recruitment","Budget impact"]};
    else if(ql.includes("vendor")||ql.includes("sla")||ql.includes("language line")||ql.includes("amn"))r={content:"\u{1F4E6} Vendor Status\n\nLanguage Line: 94.2% fill \u2714\uFE0F\nAMN: 84.1% \u26A0\uFE0F BELOW SLA (transitioning)\nInternal: 96.8% \u2B50 highest quality\nCLI: 91.5% (overflow)\nPurple VRS: 93.8% (ASL)\n\nAMN migration 72% complete. Target: Q2.\nPredicted: LLS fill may drop to 91% spring break week.\n\n\u{1F6A8} Pre-activate CLI overflow Mar 15-22.",actions:["Escalate AMN","Accelerate migration","Spring break plan"]};
    else if(ql.includes("modality")||ql.includes("routing")||ql.includes("vri")||ql.includes("opi"))r={content:"\u{1F500} Modality Routing Analysis\n\nCurrent mix: In-Person 42%, VRI 31%, OPI 27%\nOptimal mix: In-Person 38%, VRI 40%, OPI 22%\n\nShifting 15% OPI to VRI saves $1.2M/yr with no quality drop.\n\nCritical settings (surgery, oncology): In-person required.\nTelehealth: OPI/3-way VRI most efficient.\nRegistration: OPI or automated IVR.\n\nModality routing engine active for all new encounters.",actions:["View routing rules","Run cost simulation","Quality impact report"]};
    else if(ql.includes("cost")||ql.includes("budget"))r={content:"\u{1F4B5} Cost Model\n\nTotal: $42.8M\nInternal (cheapest): $0.92/min, 43% of budget\nLLS: $1.38/min, 22.4%\nAMN: $1.65/min \u2192 $0 after Q2 transition\n\nScenarios:\n\u2022 Baseline: $45.1M (+5.4%)\n\u2022 SE Expansion: $48.3M (+12.8%)\n\u2022 AI-Augmented: $46.3M (+8.2%, saves $3.8M)\n\nBiggest savings lever: +8 internal hires in SE = -$2.1M vendor spend.",actions:["Run scenario model","Hire vs vendor analysis","CFO brief"]};
    setTimeout(()=>{setMsgs(p=>[...p,{role:"agent",content:r.content,ts:new Date().toLocaleTimeString([],{hour:"2-digit",minute:"2-digit"}),actions:r.actions}]);setThinking(false);},1600);};
  const send=()=>{if(!inp.trim())return;const ts=new Date().toLocaleTimeString([],{hour:"2-digit",minute:"2-digit"});setMsgs(p=>[...p,{role:"user",content:inp,ts}]);respond(inp);setInp("");};
  useEffect(()=>{ref.current?.scrollTo({top:ref.current.scrollHeight,behavior:"smooth"});},[msgs]);
  return(<div className="flex flex-col h-full"><div className="flex items-center gap-2 px-4 py-3 border-b border-[#1e2d3d]"><div className="w-2 h-2 rounded-full bg-emerald-400 animate-pulse"/><span className="text-xs font-semibold text-[#8ab4d8] tracking-wider uppercase">Language Services Agent</span><Badge variant="outline" className="ml-auto text-[10px] border-emerald-500/30 text-emerald-400">6 Sources</Badge></div>
    <ScrollArea className="flex-1 p-4" ref={ref}><div className="space-y-3">{msgs.map((m,i)=>(<div key={i} className={`flex ${m.role==="user"?"justify-end":"justify-start"}`}><div className={`max-w-[90%] rounded-lg px-3 py-2 text-sm ${m.role==="user"?"bg-[#1a3a5c] text-[#c8dff0] border border-[#2a5a8c]":m.role==="sys"?"bg-[#0a1520] text-[#4a7a9a] border border-[#162535] font-mono text-xs":"bg-[#111f2e] text-[#a8c8e0] border border-[#1e2d3d]"}`}><div className="whitespace-pre-wrap">{m.content}</div>{m.actions&&<div className="flex flex-wrap gap-1.5 mt-2 pt-2 border-t border-[#1e2d3d]">{m.actions.map((a,j)=><button key={j} className="text-[10px] px-2 py-1 rounded bg-[#1a3a5c] text-[#8ab4d8] border border-[#2a5a8c] hover:bg-[#2a5a8c] transition-colors">{a}</button>)}</div>}</div></div>))}{thinking&&<div className="flex justify-start"><div className="bg-[#111f2e] border border-[#1e2d3d] rounded-lg px-4 py-3"><div className="flex gap-1.5">{[0,150,300].map(d=><div key={d} className="w-2 h-2 rounded-full bg-[#3a7abd] animate-bounce" style={{animationDelay:`${d}ms`}}/>)}</div></div></div>}</div></ScrollArea>
    <div className="p-3 border-t border-[#1e2d3d]"><div className="flex flex-wrap gap-1.5 mb-2">{["Demand forecast","Vendor SLA status","Modality routing analysis","Cost model scenarios"].map((q,i)=><button key={i} onClick={()=>{const ts=new Date().toLocaleTimeString([],{hour:"2-digit",minute:"2-digit"});setMsgs(p=>[...p,{role:"user",content:q,ts}]);respond(q);}} className="text-[10px] px-2 py-1 rounded-full border border-[#1e2d3d] text-[#6b8aad] hover:border-[#3a7abd] hover:text-[#8ab4d8] transition-colors">{q}</button>)}</div><div className="flex gap-2"><Input value={inp} onChange={e=>setInp(e.target.value)} onKeyDown={e=>e.key==="Enter"&&send()} placeholder="Ask about language services..." className="bg-[#0a1520] border-[#1e2d3d] text-[#c8dff0] placeholder:text-[#3a5a7a] text-sm focus-visible:ring-[#2a5a8c]"/><Button onClick={send} size="sm" className="bg-[#1a3a5c] hover:bg-[#2a5a8c] border border-[#2a5a8c]"><I.Send/></Button></div></div></div>);
}

